import{_ as t,o,c as r,a3 as a}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"171. Reasonable Additional Hours","description":"","frontmatter":{"title":"171. Reasonable Additional Hours","eba":"Mental Health Services 2024-2028","topics":["hours","overtime"]},"headers":[],"relativePath":"ebas/mental-health/support-services/preliminary/171-reasonable-additional-hours.md","filePath":"ebas/mental-health/support-services/preliminary/171-reasonable-additional-hours.md"}'),n={name:"ebas/mental-health/support-services/preliminary/171-reasonable-additional-hours.md"};function s(i,e,l,p,h,d){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="_171-reasonable-additional-hours" tabindex="-1">171. Reasonable Additional Hours <a class="header-anchor" href="#_171-reasonable-additional-hours" aria-label="Permalink to &quot;171. Reasonable Additional Hours&quot;">​</a></h1><p><strong>171.1</strong> Subject to clause 171.2, an Employer may require an Employee to work reasonable additional hours at the appropriate overtime rate as defined in clause 169 (Overtime) of this Part E.</p><p><strong>171.2</strong> An Employee may refuse to work overtime in circumstances where the working of such overtime would result in the Employee working hours which are unreasonable having regard to:</p><p><strong>(a)</strong> any risk to Employee health and safety arising from the additional hours</p><p><strong>(b)</strong> the Employee&#39;s personal circumstances, including family responsibilities</p><p><strong>(c)</strong> the needs of the workplace or enterprise in which the Employee is employed</p><p><strong>(d)</strong> whether the Employee is entitled to receive overtime payments, penalty rates or other compensation for, or a level of remuneration that reflects an expectation of, working additional hours</p><p><strong>(e)</strong> the notice (if any) given by the Employer of the overtime and by the Employee of their intention to refuse it</p><p><strong>(f)</strong> the usual patterns of work in the industry, or the part of the industry, in which the Employee works</p><p><strong>(g)</strong> the nature of the Employee’s role, and the Employee’s level of responsibility</p><p><strong>(h)</strong> whether the additional hours are in accordance with an averaging arrangement agreed to by the Employer and Employee under <a href="/eba/ebas/mental-health/support-services/preliminary/164-hours-of-work.html">clause 164</a> (Hours of Work); and</p><p><strong>(i)</strong> any other relevant matter.</p>',12)])])}const c=t(n,[["render",s]]);export{u as __pageData,c as default};
